import{_ as i,o as e,c as s,ag as t}from"./chunks/framework.BuUvxvtQ.js";const m=JSON.parse('{"title":"Типичные ошибки пользователей","description":"","frontmatter":{},"headers":[],"relativePath":"mistakes.md","filePath":"mistakes.md"}'),d={name:"mistakes.md"};function r(l,a,c,o,p,h){return e(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="типичные-ошибки-пользователеи" tabindex="-1">Типичные ошибки пользователей <a class="header-anchor" href="#типичные-ошибки-пользователеи" aria-label="Permalink to &quot;Типичные ошибки пользователей&quot;">​</a></h1><p>Ошибки в цифровой безопасности часто кажутся мелочами, но именно они создают уязвимость. Ниже перечислены самые распространенные ситуации.</p><div class="card-grid"><div class="mistake-card"><h3>Один пароль для всего</h3><p>Если пароль повторяется в разных сервисах, компрометация одного аккаунта ставит под угрозу остальные.</p></div><div class="mistake-card"><h3>Игнорирование 2FA</h3><p>Пользователь знает о дополнительной защите, но откладывает настройку, считая ее необязательной.</p></div><div class="mistake-card"><h3>Доверие к срочным сообщениям</h3><p>Человек торопится и не замечает, что ссылка или запрос на ввод кода ведут к подмене.</p></div><div class="mistake-card"><h3>Слишком открытый профиль</h3><p>Публикация личных данных облегчает подбор информации для злоупотреблений и нежелательных контактов.</p></div><div class="mistake-card"><h3>Непроверенные устройства</h3><p>После входа на чужом компьютере или старом телефоне пользователь забывает завершить сеанс.</p></div><div class="mistake-card"><h3>Передача кодов знакомым</h3><p>Даже если сообщение пришло от знакомого аккаунта, код подтверждения нельзя пересылать никому.</p></div></div><h2 id="как-уменьшить-число-ошибок" tabindex="-1">Как уменьшить число ошибок <a class="header-anchor" href="#как-уменьшить-число-ошибок" aria-label="Permalink to &quot;Как уменьшить число ошибок&quot;">​</a></h2><ol><li>Выберите один день в месяц для ревизии безопасности.</li><li>Используйте чек-лист с этого сайта как постоянную памятку.</li><li>Подключите двухфакторную аутентификацию в первую очередь на почте и мессенджерах.</li><li>Удалите лишние публичные данные из профилей.</li><li>Проверяйте контекст каждого сообщения, где просят перейти по ссылке или что-то подтвердить.</li></ol>',5)])])}const _=i(d,[["render",r]]);export{m as __pageData,_ as default};
